INSERT INTO public.creators (id, email, name, type, territory, verified, created_at)
INSERT INTO public.works
  (creator_id, title, title_original, family, year, territory, languages, description, status)
VALUES
  ('00000000-0000-0000-0000-000000000001', 'Le konpa est une musique qui vient d''Haïti. Il a été créé par…', 'Konpa se yon mizik ki soti Ayiti. Li kreye pa Nemours Jean-Baptiste nan ane 1955', 'musical', 2026, 'Haiti', ARRAY['hat'], 'Konpa se yon mizik ki soti Ayiti. Li kreye pa Nemours Jean-Baptiste nan ane 1955. Jodi a, konpa jwe toupatou nan mond lan.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le gwo ka est une musique traditionnelle de Guadeloupe. Elle vient…', 'Gwoka sé yon mizik tradisyonèl Gwadloup. I sòti dé tan lesklaj. Jodi-a, lépatrim', 'musical', 2026, 'Guadeloupe', ARRAY['gcf'], 'Gwoka sé yon mizik tradisyonèl Gwadloup. I sòti dé tan lesklaj. Jodi-a, lépatrimowan imensyèl limanité UNESCO rekonèt li.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le bèlè est une danse traditionnelle de Martinique. Il associe…', 'Bèlè sé an dans tradisyonèl Matinik. I rélé ansamn tanbou, chante épi dans. Bèlè', 'performing_arts', 2026, 'Martinique', ARRAY['acf'], 'Bèlè sé an dans tradisyonèl Matinik. I rélé ansamn tanbou, chante épi dans. Bèlè sé yon pratik kiltirèl ki rété vivan jòdi-a.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La musique reggae vient de Jamaïque dans les années 1960. Bob Marley…', 'Reggae music come from Jamaica inna di 1960s. Bob Marley mek it famous worldwide', 'musical', 2026, 'Jamaica', ARRAY['jam'], 'Reggae music come from Jamaica inna di 1960s. Bob Marley mek it famous worldwide. Di riddim slow and steady, and di lyrics talk bout justice and freedom.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le carnaval d''Aruba est l''un des plus grands des Caraïbes. Le tumba…', 'Karnaval di Aruba ta uno di mas grandi den Caribe. Tumba ta e musica oficial di ', 'performing_arts', 2026, 'Aruba', ARRAY['pap'], 'Karnaval di Aruba ta uno di mas grandi den Caribe. Tumba ta e musica oficial di Karnaval. Cada aña, artistanan ta kompiti pa titulo di Rey o Reina di Tumba.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Zouk — Caribbean (général)', 'Le zouk est une musique originaire des Antilles françaises, créée dans les année', 'musical', 2026, 'Caribbean (général)', ARRAY['fra'], 'Le zouk est une musique originaire des Antilles françaises, créée dans les années 1980 par le groupe Kassav''. Son rythme entraînant et ses mélodies romantiques en ont fait un succès mondial.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le son cubain est l''un des genres musicaux les plus influents des…', 'El son cubano es uno de los géneros musicales más influyentes del Caribe. Surgió', 'musical', 2026, 'Cuba', ARRAY['spa'], 'El son cubano es uno de los géneros musicales más influyentes del Caribe. Surgió en la región oriental de Cuba a finales del siglo XIX y es el precursor directo de la salsa.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La musique calypso est originaire de Trinidad-et-Tobago au début du…', 'Calypso music originated in Trinidad and Tobago in the early 20th century. It ev', 'musical', 2026, 'Trinidad', ARRAY['eng'], 'Calypso music originated in Trinidad and Tobago in the early 20th century. It evolved into soca in the 1970s. Both genres are central to Trinidad Carnival, one of the largest in the world.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Konpa — Haiti', 'Reconnaissance historique pour Haïti : le konpa inscrit officiellement au patrim', 'musical', 2026, 'Haiti', ARRAY['fra'], 'Reconnaissance historique pour Haïti : le konpa inscrit officiellement au patrimoine immatériel de l''humanité de l''UNESCO. Ce mercredi 10 décembre 2025, le konpa, genre musical et danse emblématiques d''Haïti, a officiellement rejoint la liste du patrimoine culturel immatériel de l''humanité de l''UNESCO.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Gwo Ka — Guadeloupe', 'Gwoka et bèlè : rencontres croisées. Un bokantaj entre îles sœurs, Guadeloupe et', 'musical', 2026, 'Guadeloupe', ARRAY['fra'], 'Gwoka et bèlè : rencontres croisées. Un bokantaj entre îles sœurs, Guadeloupe et Martinique a lieu autour de deux traditions majeures de la Caraïbe, le gwoka et le bèlè. Au programme : résidence d''artistes, soirées culturelles et concerts. Au son du tambour, sa mémoire, son langage, un relais et même un trait d''union se fait entre deux îles sœurs.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Quadrille Creole — Guadeloupe', 'Les quadrilles créoles de Guadeloupe entrent au patrimoine culturel immatériel n', 'performing_arts', 2026, 'Guadeloupe', ARRAY['fra'], 'Les quadrilles créoles de Guadeloupe entrent au patrimoine culturel immatériel national. Le 17 décembre 2025, la ministre française de la Culture Rachida Dati a reçu une délégation guadeloupéenne afin de leur remettre le diplôme d''inscription des quadrilles créoles à l''Inventaire national du patrimoine culturel immatériel. Issues de l''histoire de l''esclavage colonial, ces danses transmises de géné', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Bele — Martinique', 'AM4 : quarante ans à faire vivre la culture martiniquaise. L''association AM4 - M', 'performing_arts', 2026, 'Martinique', ARRAY['fra'], 'AM4 : quarante ans à faire vivre la culture martiniquaise. L''association AM4 - Mi Mès Manmay Matinik - dont le nom signifie en créole « Voici les mœurs et coutumes martiniquaises » - célèbre quatre décennies d''engagement au service de la culture martiniquaise. Fondée en 1986, la structure travaille à la sauvegarde et à la transmission du bèlè, du danmyé ou encore de la kalenda. « Nou kontan. É an ', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Chante Noel — Martinique', 'Moman Chanté : faire vivre autrement le patrimoine musical martiniquais. Georges', 'musical', 2026, 'Martinique', ARRAY['fra'], 'Moman Chanté : faire vivre autrement le patrimoine musical martiniquais. Georges Gromat, alias Joko, propose des moments conviviaux autour de la musique antillo-guyanaise. Les livrets réalisés durant le confinement répertorient plus de 560 titres du patrimoine musical martiniquais. Comme dans le chanté Noël, il y a un meneur qui donne le numéro des pages avec les ti-bwa.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus education — Caribbean (général)', 'CreoleVal est une collection de benchmarks NLP couvrant 28 langues créoles dont ', 'heritage', 2026, 'Caribbean (général)', ARRAY['eng'], 'CreoleVal est une collection de benchmarks NLP couvrant 28 langues créoles dont le créole haïtien (hat), le créole guadeloupéen (gcf), le créole antillais (acf) et le papiamentu (pap). Publié dans Transactions of the Association for Computational Linguistics en 2024, ce projet vise à développer des ressources linguistiques pour des langues sous-dotées issues de l''histoire coloniale.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus education — Caribbean (général)', 'Kreyòl-MT: Building MT for Latin American, Caribbean and Colonial African Creole', 'heritage', 2026, 'Caribbean (général)', ARRAY['eng'], 'Kreyòl-MT: Building MT for Latin American, Caribbean and Colonial African Creole Languages. The largest, most genre-diverse MT datasets ever compiled for 41 Creole languages, including the first ever for 21 Creole languages. A public dataset of 11.6M aligned sentences and 3.4M monolingual sentences for 40 Creole languages.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Enfant, souviens-toi de qui tu es. N''oublie jamais d''où tu viens.…', 'Yich, sonjé ki moun ou yé. Pa janmen bliyé koté ou sòti. Rasin ou, sé sa ki fè o', 'literary', 2026, 'Guadeloupe', ARRAY['gcf'], 'Yich, sonjé ki moun ou yé. Pa janmen bliyé koté ou sòti. Rasin ou, sé sa ki fè ou doubout. Zansèt ou pa janmen mouri si ou pa bliyé yo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L''eau qui coule ne revient jamais. Mais les racines de l''arbre…', 'Dlo ki kouri pa janm tounen. Men rasin pye bwa a rete anba tè a, li pa janm kite', 'literary', 2026, 'Haiti', ARRAY['hat'], 'Dlo ki kouri pa janm tounen. Men rasin pye bwa a rete anba tè a, li pa janm kite. Se konsa nou ye : nou ka deplase, nou pa ka dezansinen.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Yé krik ! Yé krak ! Les anciens disaient : si tu ne te connais pas…', 'Yé krik ! Yé krak ! Vié moun té di : si ou pa konn kò ou, lòt moun ké konn li po', 'literary', 2026, 'Martinique', ARRAY['acf'], 'Yé krik ! Yé krak ! Vié moun té di : si ou pa konn kò ou, lòt moun ké konn li pou ou. Sé pou sa nou aprann palénou, chanté nou, dansé nou.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les anciens disaient : si tu ne sais pas d''où tu viens, tu ne peux…', 'Di old people dem seh : if you nuh know where you come from, you cyan know where', 'literary', 2026, 'Jamaica', ARRAY['jam'], 'Di old people dem seh : if you nuh know where you come from, you cyan know where you going. Di Maroon dem never forget. Even inna di mountains, dem keep di memory alive.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Celui qui ne connaît pas son histoire est condamné à la répéter.…', 'El que no conoce su historia está condenado a repetirla. Pero el que sí la conoc', 'literary', 2026, 'Cuba', ARRAY['spa'], 'El que no conoce su historia está condenado a repetirla. Pero el que sí la conoce tiene el poder de cambiarla. Eso nos enseñaron los viejos del barrio desde que éramos niños.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le rara est la fête du peuple. Dans les rues, sur les chemins, la…', 'Rara sé fèt pèp la. Nan lari yo, nan chemen yo, mizik la monte, kò yo bouje. Se ', 'heritage', 2026, 'Haiti', ARRAY['hat'], 'Rara sé fèt pèp la. Nan lari yo, nan chemen yo, mizik la monte, kò yo bouje. Se yon tradisyon ki viv depi lontan, ki paka mouri paske li nan san nou.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le Rastafari n''est pas seulement une religion — c''est un mode de…', 'Rastafari nuh just religion — a way of life, a vision of dignity. Ital food, nat', 'heritage', 2026, 'Jamaica', ARRAY['jam'], 'Rastafari nuh just religion — a way of life, a vision of dignity. Ital food, natural living, the reasoning sessions — all of it say : we are not what dem tell us we were. We are kings and queens.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le gwo-ka a été classé patrimoine immatériel de l''humanité par…', 'Gwo-ka klase patrimwan imensyèl limanité pa UNESCO an 2014. Men avan sa, i té dé', 'heritage', 2026, 'Guadeloupe', ARRAY['gcf'], 'Gwo-ka klase patrimwan imensyèl limanité pa UNESCO an 2014. Men avan sa, i té déja nan kè tout Gwadloupéyen. Tanbou-a palé douvan lézòm, i palé douvan Bondié.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'J''écris en créole parce que c''est ma langue. La langue de ma mère,…', 'Mwen ékri an kréyol paské sé lang mwen. Lang manman mwen, lang gran-manman mwen.', 'literary', 2026, 'Guadeloupe', ARRAY['gcf'], 'Mwen ékri an kréyol paské sé lang mwen. Lang manman mwen, lang gran-manman mwen. Lang ki té entèrdi, ki té pini, ki rivé doubout kanmenm. Chak mo kréyol sé yon viktwa.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Écrire en créole est un acte politique. C''est dire : ma langue a de…', 'Ecrire an kreyòl se yon aksyon politik. Se di : lang mwen gen valè. Listwa mwen ', 'literary', 2026, 'Haiti', ARRAY['hat'], 'Ecrire an kreyòl se yon aksyon politik. Se di : lang mwen gen valè. Listwa mwen gen valè. Mwen pa bezwen tradiksyon pou egziste. Mwen ekziste nan pwòp vwa mwen.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus literature — Diaspora caribéenne', 'Nous portons les îles dans nos corps même quand nous vivons loin. La mer ne nous', 'literary', 2026, 'Diaspora caribéenne', ARRAY['fra'], 'Nous portons les îles dans nos corps même quand nous vivons loin. La mer ne nous quitte pas. Elle revient dans nos rêves, dans nos plats, dans la façon dont nous parlons à nos enfants la nuit.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le vodou n''est pas quelque chose à craindre. C''est un système de…', 'Vodou se pa yon bagay pou pè. Se yon sistèm kwayans ki soti nan Afrik, ki pase n', 'heritage', 2026, 'Haiti', ARRAY['hat'], 'Vodou se pa yon bagay pou pè. Se yon sistèm kwayans ki soti nan Afrik, ki pase nan doulè esklavaj, ki rive jouk jodi a. Li kenbe pèp ayisyen kanpe lè tout bagay te vle kraze yo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le culte des Orishas à Trinidad nous connecte directement aux…', 'Orisha worship in Trinidad connects us directly to the Yoruba ancestors who cros', 'heritage', 2026, 'Trinidad', ARRAY['eng'], 'Orisha worship in Trinidad connects us directly to the Yoruba ancestors who crossed the Middle Passage. The prayers, the rhythms, the colours — all of it survived. All of it is still here.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La cuisine créole c''est notre identité. Colombo, boudin, acras,…', 'Manjé kréyol sé idantité nou. Kolombò, boudin, acras, chatrou — chak plat kont y', 'heritage', 2026, 'Guadeloupe', ARRAY['gcf'], 'Manjé kréyol sé idantité nou. Kolombò, boudin, acras, chatrou — chak plat kont yon listwa. Chak odè rappòté souvni. Mété douvan yon asyet kréyol, ou mété douvan tout yon kilti.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le drapeau dominicain — riz, haricots et viande — n''est pas…', 'La bandera dominicana — arroz, habichuelas y carne — no es solo comida. Es ident', 'heritage', 2026, 'Dominican Republic', ARRAY['spa'], 'La bandera dominicana — arroz, habichuelas y carne — no es solo comida. Es identidad, es familia, es el olor de la casa de la abuela. Cada día, millones de dominicanos comen lo mismo y se reconocen en ello.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le Carnaval de Trinidad est le plus grand spectacle sur terre. Ce…', 'Trinidad Carnival is the greatest show on earth. Is not just costume and music —', 'performing_arts', 2026, 'Trinidad', ARRAY['eng'], 'Trinidad Carnival is the greatest show on earth. Is not just costume and music — is identity, is history, is the soul of a whole people pouring itself into the streets. When mas comes out, we remember who we are.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La tumba est le rythme de notre cœur. Chaque année, au temps du…', 'Tumba ta e ritmo di nos kurason. Kada aña, na tempu di Karnaval, e muzik ta uní ', 'performing_arts', 2026, 'Aruba', ARRAY['pap'], 'Tumba ta e ritmo di nos kurason. Kada aña, na tempu di Karnaval, e muzik ta uní nos tur — Arubano, Korsouenyo, Bonairiano — den un sola vos di alegria i orguyo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le kaseko est une musique du Suriname. Il vient d''Afrique et…', 'Kaseko na wan muziek fu Sranan. A komopo fu Afrika en Eroupa. Den sma dansi na a', 'musical', 2026, 'Suriname', ARRAY['srn'], 'Kaseko na wan muziek fu Sranan. A komopo fu Afrika en Eroupa. Den sma dansi na a ritmo fu kaseko na ala fesa.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Nous ne devons pas oublier d''où nous venons. Les ancêtres vivaient…', 'Wi no mag fergriti pe wi komopo. Den baka-ten sma ben libi na mofo-watra. Wi mus', 'literary', 2026, 'Suriname', ARRAY['srn'], 'Wi no mag fergriti pe wi komopo. Den baka-ten sma ben libi na mofo-watra. Wi musu tyari den tori gi wi pikin.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les Marrons ont fui dans la forêt pour échapper à l''esclavage.…', 'Den Maroon sma ben lowe go na busu fu figi den srafu-ten. Nownow, den kulturu li', 'heritage', 2026, 'Suriname', ARRAY['srn'], 'Den Maroon sma ben lowe go na busu fu figi den srafu-ten. Nownow, den kulturu libi go doro. Saramaka, Ndyuka, Kwinti — ala den e hori den olo kulturu.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le Sranan Tongo est la langue de tous les Surinamiens. Ce n''est pas…', 'Sranan Tongo na wan tongo fu ala Sranan sma. A no wan tongo fu wan enkri groep. ', 'heritage', 2026, 'Suriname', ARRAY['srn'], 'Sranan Tongo na wan tongo fu ala Sranan sma. A no wan tongo fu wan enkri groep. A na wi ala tongo. Foe wi kan taki wan na wan, wi musu sabi a tongo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le tumba est la musique du coeur caribéen. Chaque année pendant le…', 'Tumba is de muziek van het Caribische hart. Elk jaar tijdens Carnaval strijden d', 'musical', 2026, 'Curacao', ARRAY['nld'], 'Tumba is de muziek van het Caribische hart. Elk jaar tijdens Carnaval strijden de artiesten om de titel van Rei of Reina di Tumba. De hele gemeenschap komt samen om te luisteren en te dansen.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les anciens disaient toujours : connais tes racines, connais ta…', 'De oude mensen zeiden altijd : ken je roots, ken je taal, ken je cultuur. Zonder', 'literary', 2026, 'Curacao', ARRAY['nld'], 'De oude mensen zeiden altijd : ken je roots, ken je taal, ken je cultuur. Zonder die kennis ben je een boom zonder wortels. De wind kan je dan omverwaaien.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le carnaval d''Aruba est plus qu''une fête. C''est une expression…', 'Het carnaval van Aruba is meer dan een feest. Het is een culturele uitdrukking v', 'performing_arts', 2026, 'Aruba', ARRAY['nld'], 'Het carnaval van Aruba is meer dan een feest. Het is een culturele uitdrukking van wie wij zijn. De muziek, de kostuums, de dans — alles vertelt het verhaal van ons volk.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le Suriname est un pays de nombreuses cultures et langues.…', 'Suriname is een land van vele culturen en talen. Hindoestani, Javaans, Creools, ', 'heritage', 2026, 'Suriname', ARRAY['nld'], 'Suriname is een land van vele culturen en talen. Hindoestani, Javaans, Creools, Maroon, Inheems — al deze culturen leven samen en vormen de rijkdom van ons land.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus theatre — Martinique', 'Le théâtre créole martiniquais porte une tradition vivante. Les pièces en créole', 'performing_arts', 2026, 'Martinique', ARRAY['fra'], 'Le théâtre créole martiniquais porte une tradition vivante. Les pièces en créole mêlent conte, musique et danse. Chaque représentation est un acte de résistance culturelle autant qu''un moment de joie collective.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le théâtre du Carnaval à Trinidad est une forme d''art vivante. Le…', 'Carnival theatre in Trinidad is a living art form. The character of Midnight Rob', 'performing_arts', 2026, 'Trinidad', ARRAY['eng'], 'Carnival theatre in Trinidad is a living art form. The character of Midnight Robber, the Dame Lorraine, the Jab Jab — each mas character carries centuries of storytelling, resistance, and memory.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le théâtre créole dit qui nous sommes. Quand l''acteur monte sur…', 'Téyat kréyol la di sé ki nou yé. Lè aktè-a monté sou sèn-an ék i palé kréyol, to', 'performing_arts', 2026, 'Guadeloupe', ARRAY['gcf'], 'Téyat kréyol la di sé ki nou yé. Lè aktè-a monté sou sèn-an ék i palé kréyol, tout moun nan sal-la santi yé ki lakay yo. Téyat sé miwa a pèp-la.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le théâtre haïtien parle dans la langue du peuple. Il n''a pas besoin…', 'Teyat ayisyen an pale nan lang pèp la. Li pa bezwen tradiksyon. Li pale dirèk na', 'performing_arts', 2026, 'Haiti', ARRAY['hat'], 'Teyat ayisyen an pale nan lang pèp la. Li pa bezwen tradiksyon. Li pale dirèk nan kè moun. Depi tan lontan, teyat te yon fason pou di verite lè pa t kapab pale tout kote.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus visual_arts — Haiti', 'La peinture haïtienne est connue dans le monde entier pour ses couleurs vives et', 'visual_arts', 2026, 'Haiti', ARRAY['fra'], 'La peinture haïtienne est connue dans le monde entier pour ses couleurs vives et sa spiritualité. Les artistes de l''École de la Belle Époque ont peint un Haïti vibrant, mystique et plein de vie.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L''art jamaïcain raconte l''histoire d''un peuple qui a refusé d''être…', 'Jamaican art tells the story of a people who refused to be invisible. From the i', 'visual_arts', 2026, 'Jamaica', ARRAY['eng'], 'Jamaican art tells the story of a people who refused to be invisible. From the intuitive painters of the 1950s to the contemporary street murals of Kingston — every brushstroke is an act of self-definition.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La peinture, la sculpture, la photographie — toutes les formes d''art…', 'Penti-a, skiltè-a, fotograf-la — tout fòm a la an ka di listwa-nou. Atizan gwadl', 'visual_arts', 2026, 'Guadeloupe', ARRAY['gcf'], 'Penti-a, skiltè-a, fotograf-la — tout fòm a la an ka di listwa-nou. Atizan gwadloupéyen yo ka travay pou vizibilité kilti-nou. Lè yo kréyé, yo di : nou la, nou egzisté.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L''art cubain parle de contradictions, de beauté et de lutte. De…', 'El arte cubano habla de contradicciones, de belleza y de lucha. Desde Wilfredo L', 'visual_arts', 2026, 'Cuba', ARRAY['spa'], 'El arte cubano habla de contradicciones, de belleza y de lucha. Desde Wilfredo Lam hasta los artistas jóvenes de La Habana, el arte cubano es un diálogo constante entre la tradición africana, europea y americana.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus news — Guadeloupe', 'Les médias caribéens francophones jouent un rôle essentiel dans la circulation d', 'literary', 2026, 'Guadeloupe', ARRAY['fra'], 'Les médias caribéens francophones jouent un rôle essentiel dans la circulation de l''information locale. France-Antilles, RCI, Guadeloupe La 1ère — ces médias portent la voix des Antilles vers leurs communautés.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le journalisme caribéen a toujours dû lutter pour son indépendance.…', 'Caribbean journalism has always had to fight for independence. From the early fr', 'literary', 2026, 'Trinidad', ARRAY['eng'], 'Caribbean journalism has always had to fight for independence. From the early freedom press of the colonial era to the digital newsrooms of today, the Caribbean press has been a space for political debate and cultural affirmation.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La radio en Haïti est un outil important pour communiquer avec le…', 'Radyo ann Ayiti se yon zouti enpòtan pou kominike ak pèp la. Depi lontan, radyo ', 'literary', 2026, 'Haiti', ARRAY['hat'], 'Radyo ann Ayiti se yon zouti enpòtan pou kominike ak pèp la. Depi lontan, radyo te pale kreyòl lè lòt mwayen pa t aksesib. Li te yon plas pou nouvèl, pou mizik, pou pale ak chak lòt.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La presse dominicaine a une longue histoire de défense de la vérité.…', 'La prensa dominicana tiene una historia larga de defender la verdad. Periodistas', 'literary', 2026, 'Dominican Republic', ARRAY['spa'], 'La prensa dominicana tiene una historia larga de defender la verdad. Periodistas que arriesgaron su vida para informar al pueblo, en tiempos de dictadura y en democracia. El periodismo es una forma de patriotismo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus social_media — Caribbean (général)', 'Les créateurs caribéens investissent massivement les réseaux sociaux pour contou', 'literary', 2026, 'Caribbean (général)', ARRAY['fra'], 'Les créateurs caribéens investissent massivement les réseaux sociaux pour contourner les circuits de distribution traditionnels. TikTok, Instagram, YouTube deviennent des espaces de visibilité culturelle directe.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les créateurs caribéens construisent des audiences sans attendre les…', 'Caribbean content creators are building audiences without waiting for gatekeeper', 'literary', 2026, 'Caribbean (général)', ARRAY['eng'], 'Caribbean content creators are building audiences without waiting for gatekeepers. The algorithm may not understand our culture yet — but we are teaching it, one video at a time.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les créateurs de contenu guadeloupéens utilisent les réseaux sociaux…', 'Kréatè kontant gwadloupéyen yo ka itilizé rézo sosyal pou fè kilti-yo vizib. You', 'literary', 2026, 'Guadeloupe', ARRAY['gcf'], 'Kréatè kontant gwadloupéyen yo ka itilizé rézo sosyal pou fè kilti-yo vizib. YouTube, TikTok, Instagram — sé plas-la yo ka palé kréyol, yo ka monté mizik-yo, yo ka di ki yo yé.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les jeunes haïtiens créent du contenu sur internet. Ils parlent…', 'Jenès ayisyen yo ap kreye kontni sou entènèt. Yo pale kreyòl, yo montre kilti yo', 'literary', 2026, 'Haiti', ARRAY['hat'], 'Jenès ayisyen yo ap kreye kontni sou entènèt. Yo pale kreyòl, yo montre kilti yo, yo ri ansanm. Rezo sosyal yo tounen yon plas pou idantite ayisyèn an viv ak grandi.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le merengue est l''âme de la République Dominicaine. Déclaré…', 'El merengue es el alma de la República Dominicana. Declarado patrimonio de la hu', 'musical', 2026, 'Dominican Republic', ARRAY['spa'], 'El merengue es el alma de la República Dominicana. Declarado patrimonio de la humanidad por la UNESCO en 2016, el merengue nació en el campo y conquistó el mundo entero.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La bachata est née en marge, dans les bars modestes des quartiers…', 'La bachata nació en los márgenes, en los bares humildes de los barrios pobres. F', 'musical', 2026, 'Dominican Republic', ARRAY['spa'], 'La bachata nació en los márgenes, en los bares humildes de los barrios pobres. Fue rechazada por las élites, amada por el pueblo. Hoy es escuchada en todo el mundo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La musique bouyon de la Dominique est énergie pure. Elle mélange la…', 'Bouyon music from Dominica is raw energy. It mixes cadence, reggae, and soca int', 'musical', 2026, 'Dominica', ARRAY['eng'], 'Bouyon music from Dominica is raw energy. It mixes cadence, reggae, and soca into something uniquely Dominican. When bouyon plays, the whole island moves as one body.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le kadans-lypso est une musique née à la Martinique. Il mélange les…', 'Kadans-lypso sé yon mizik ki né Matinik. I mélanjé ritem afrikèn épi melodi erop', 'musical', 2026, 'Martinique', ARRAY['acf'], 'Kadans-lypso sé yon mizik ki né Matinik. I mélanjé ritem afrikèn épi melodi eropéyèn. Gran non tankou Jacob Desvarieux té pòté l'' toupatou adan mond-lan.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le ska était la première musique que la Jamaïque a donnée au monde.…', 'Ska was the first music Jamaica gave to the world. Before reggae, before danceha', 'musical', 2026, 'Jamaica', ARRAY['jam'], 'Ska was the first music Jamaica gave to the world. Before reggae, before dancehall — there was ska. Fast, joyful, irresistible. It came out of independence and it sounded like freedom.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La Barbade a son âme musicale propre. De la tradition calypso aux…', 'Barbados has its own musical soul. From the calypso tradition to the modern soca', 'musical', 2026, 'Barbados', ARRAY['eng'], 'Barbados has its own musical soul. From the calypso tradition to the modern soca festivals, Bajan music is a celebration of resilience and joy. Crop Over is not just a festival — it is a declaration of life.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Sainte-Lucie se situe entre les traditions caribéennes française et…', 'Saint Lucia sits between French and English Caribbean traditions. Its music refl', 'musical', 2026, 'St Lucia', ARRAY['eng'], 'Saint Lucia sits between French and English Caribbean traditions. Its music reflects that — creole rhythms, English lyrics, French melodies. The island is a living example of Caribbean cultural mixing.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Porto Rico est la capitale mondiale de la salsa. Du Gran Combo à…', 'Puerto Rico es la capital mundial de la salsa. Desde El Gran Combo hasta Calle 1', 'musical', 2026, 'Puerto Rico', ARRAY['spa'], 'Puerto Rico es la capital mundial de la salsa. Desde El Gran Combo hasta Calle 13, la música puertorriqueña ha definido el sonido del Caribe hispano por décadas.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les contes de ma grand-mère m''ont appris davantage sur ce qu''est…', 'Los cuentos de mi abuela me enseñaron más sobre ser puertorriqueño que cualquier', 'literary', 2026, 'Puerto Rico', ARRAY['spa'], 'Los cuentos de mi abuela me enseñaron más sobre ser puertorriqueño que cualquier libro. Las historias de los jíbaros, de los santos, de los espíritus — todo eso vive en las palabras que se pasan de generación en generación.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le conte est pour tout le monde. Vieux, jeunes, enfants. Quand la…', 'Kont-la sé pou tout moun. Vié moun, jenn moun, piti moun. Lè gran-manman kont, t', 'literary', 2026, 'Martinique', ARRAY['acf'], 'Kont-la sé pou tout moun. Vié moun, jenn moun, piti moun. Lè gran-manman kont, tout moun doubout. Parol-la ka vwayajé, parol-la ka rété, parol-la pa ka mouri.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Dans notre culture, les histoires de nos grands-parents continuent…', 'Den nos kultura, e tori di nos grandinan ta keda biba. Nan konversashon, nan kan', 'literary', 2026, 'Curacao', ARRAY['pap'], 'Den nos kultura, e tori di nos grandinan ta keda biba. Nan konversashon, nan kantika, nan proverbio. Un pueblo sin memoria ta un pueblo sin futuro.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La musique d''Aruba est un mélange d''influences. Tumba, soca, reggae…', 'Musika di Aruba ta un mezcla di influensianan. Tumba, soca, reggae — tur esaki t', 'musical', 2026, 'Aruba', ARRAY['pap'], 'Musika di Aruba ta un mezcla di influensianan. Tumba, soca, reggae — tur esaki ta forma parti di nos identidad musikal. Nos ta Caribense i nos musika ta mustra esey.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les pratiques spirituelles en Martinique sont un mélange.…', 'Pratik spirityèl nan Matinik sé yon mélanj. Katolisism, kwayans afriken, tradisy', 'heritage', 2026, 'Martinique', ARRAY['acf'], 'Pratik spirityèl nan Matinik sé yon mélanj. Katolisism, kwayans afriken, tradisyon endijèn — tout sa yo mélanjé pou fòmé kwayans a pèp matinikè-a. Sé richès a nou.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La foi a toujours été centrale dans la vie caribéenne. L''église, les…', 'Faith has always been central to Caribbean life. The church, the revival meeting', 'heritage', 2026, 'Barbados', ARRAY['eng'], 'Faith has always been central to Caribbean life. The church, the revival meeting, the obeah tradition — all of them represent ways Caribbean people made sense of suffering, found community, and kept hope alive.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La foi fait partie de la vie guadeloupéenne. L''église, les esprits,…', 'La fwa sé pati a lavi gwadloupéyen. Légliz, lespri, zansèt — tout sa yo mélanjé ', 'heritage', 2026, 'Guadeloupe', ARRAY['gcf'], 'La fwa sé pati a lavi gwadloupéyen. Légliz, lespri, zansèt — tout sa yo mélanjé nan kilti-nou. Ou ka al légliz dimanch ék ou ka rispèkté zansèt-ou lendi. Sé pa kontradiksyon, sé richès.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La cuisine haïtienne est une expression culturelle. Riz collé aux…', 'Manje ayisyen an se yon ekspresyon kilti. Diri kole ak pwa, griot, poul nan sos ', 'heritage', 2026, 'Haiti', ARRAY['hat'], 'Manje ayisyen an se yon ekspresyon kilti. Diri kole ak pwa, griot, poul nan sos — chak plat gen yon listwa. Lè ou manje manje ayisyen, ou manje yon pèp, ou manje yon memwa.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La cuisine jamaïcaine est une cuisine de l''âme. Ackee et morue,…', 'Jamaican food is soul food. Ackee and saltfish, jerk chicken, rice and peas — ev', 'heritage', 2026, 'Jamaica', ARRAY['jam'], 'Jamaican food is soul food. Ackee and saltfish, jerk chicken, rice and peas — every dish tells the story of African roots, colonial history and Caribbean creativity. When you eat Jamaican, you eat history.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La cuisine trinidadienne est le reflet de son âme multiculturelle.…', 'Trinidadian food is a reflection of its multicultural soul. Doubles, roti, pelau', 'heritage', 2026, 'Trinidad', ARRAY['eng'], 'Trinidadian food is a reflection of its multicultural soul. Doubles, roti, pelau, callaloo — Indian, African, Chinese and European flavours all live together on the same plate. That is Trinidad.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La cuisine martiniquaise c''est notre identité. Colombo, boudin,…', 'Manjé matinikè-a sé idantité-nou. Colombo, boudin, chatrou, accras — chak plat k', 'heritage', 2026, 'Martinique', ARRAY['acf'], 'Manjé matinikè-a sé idantité-nou. Colombo, boudin, chatrou, accras — chak plat ka rakonté yon listwa. Lè ou manjé matinikè, ou ka goûté tout yon kilti, tout yon pèp.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La cuisine cubaine est métissage dans l''assiette. Ropa vieja, moros…', 'La cocina cubana es mestizaje en el plato. Ropa vieja, moros y cristianos, tosto', 'heritage', 2026, 'Cuba', ARRAY['spa'], 'La cocina cubana es mestizaje en el plato. Ropa vieja, moros y cristianos, tostones — cada plato lleva dentro la historia de África, España y el Caribe. Comer cubano es recordar quiénes somos.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Bouyon, féroce, matété crabe — notre cuisine n''est pas seulement…', 'Bouyon, féroce, matété krab — manjé-nou pa sèlman bon, i rasi. Chak fwa ou mété ', 'heritage', 2026, 'Guadeloupe', ARRAY['gcf'], 'Bouyon, féroce, matété krab — manjé-nou pa sèlman bon, i rasi. Chak fwa ou mété yon asyet kréyol douvan ou, ou ka santi rasin-ou. Kyizin gwadloupéyenn sé patrimwan-nou.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus education — Caribbean (général)', 'Enseigner en créole, c''est reconnaître que la langue de l''enfant est une langue ', 'heritage', 2026, 'Caribbean (général)', ARRAY['fra'], 'Enseigner en créole, c''est reconnaître que la langue de l''enfant est une langue valide, une langue de pensée, une langue d''apprentissage. Ce n''est pas un obstacle à l''éducation — c''est une ressource.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L''éducation caribéenne doit refléter la réalité caribéenne. Quand…', 'Caribbean education must reflect Caribbean reality. When children see themselves', 'heritage', 2026, 'Caribbean (général)', ARRAY['eng'], 'Caribbean education must reflect Caribbean reality. When children see themselves in textbooks — their history, their languages, their heroes — they understand that knowledge belongs to them too.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Quand les enfants apprennent dans leur langue, ils comprennent plus…', 'Lè timoun aprann nan lang yo, yo konprann pi vit, yo retni pi fasil, yo konfyan ', 'heritage', 2026, 'Haiti', ARRAY['hat'], 'Lè timoun aprann nan lang yo, yo konprann pi vit, yo retni pi fasil, yo konfyan nan tèt yo. Edikasyon kreyòl pa opoze ak fransè. Li se baz pou aprann fransè pi byen.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Apprendre le créole à l''école c''est dire à l''enfant : ta langue est…', 'Aprann kréyol a lékol sé di a timoun-la : lang ou sé yon richès. Sé di : ou ka r', 'heritage', 2026, 'Guadeloupe', ARRAY['gcf'], 'Aprann kréyol a lékol sé di a timoun-la : lang ou sé yon richès. Sé di : ou ka réyési adan lang-ou. Sé ba yo yon baz solid pou yo ka grandi douvan.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus general — Caribbean (général)', 'La Caraïbe n''est pas une périphérie. Elle est un carrefour. Un lieu où les civil', 'heritage', 2026, 'Caribbean (général)', ARRAY['fra'], 'La Caraïbe n''est pas une périphérie. Elle est un carrefour. Un lieu où les civilisations se sont rencontrées, affrontées, mélangées. Cette complexité est notre richesse, pas notre faiblesse.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La Caraïbe n''est pas une note de bas de page dans l''histoire…', 'The Caribbean is not a footnote in world history. It is where modernity was born', 'heritage', 2026, 'Caribbean (général)', ARRAY['eng'], 'The Caribbean is not a footnote in world history. It is where modernity was born — in the violence of colonialism, in the resistance of enslaved people, in the creolization of cultures. We are the center, not the margin.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Haïti a été le premier pays noir à se libérer de l''esclavage. C''est…', 'Ayiti te premye peyi nwa ki te libere tèt li nan esklavaj. Sa se yon istwa ki po', 'heritage', 2026, 'Haiti', ARRAY['hat'], 'Ayiti te premye peyi nwa ki te libere tèt li nan esklavaj. Sa se yon istwa ki pou tout mond lan. Revolisyon ayisyen an chanje direksyon listwa. Li di : libète posib.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La Caraïbe est une même entité même si elle parle plusieurs langues.…', 'El Caribe es uno solo aunque hable muchas lenguas. El mar nos une, la historia n', 'heritage', 2026, 'Caribbean (général)', ARRAY['spa'], 'El Caribe es uno solo aunque hable muchas lenguas. El mar nos une, la historia nos une, la lucha nos une. Más allá del español, el francés, el inglés, el papiamento — somos un mismo pueblo caribeño.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La Caraïbe est un seul peuple qui parle plusieurs langues. La mer ne…', 'Karayib-la sé yon sèl pèp ki palé plizié lang. Lanmè-a pa séparé-nou, i yonn-nou', 'heritage', 2026, 'Guadeloupe', ARRAY['gcf'], 'Karayib-la sé yon sèl pèp ki palé plizié lang. Lanmè-a pa séparé-nou, i yonn-nou. Madinina, Ayiti, Jamaïk, Gwadloup — nou tout sé yich a menm rasin.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La Jamaïque est petite mais puissante. De Marcus Garvey à Bob Marley…', 'Jamaica small but Jamaica mighty. From Marcus Garvey to Bob Marley to Usain Bolt', 'heritage', 2026, 'Jamaica', ARRAY['jam'], 'Jamaica small but Jamaica mighty. From Marcus Garvey to Bob Marley to Usain Bolt — this little island keep producing people who change the world. That is not accident. That is spirit.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Corpus general — Diaspora caribéenne', 'La diaspora caribéenne porte les îles partout où elle va. À Paris, à New York, à', 'heritage', 2026, 'Diaspora caribéenne', ARRAY['fra'], 'La diaspora caribéenne porte les îles partout où elle va. À Paris, à New York, à Londres, à Montréal — les Caribéens reconstruisent leur culture, transmettent leurs langues, gardent leurs liens.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La diaspora caribéenne n''est pas seulement une communauté à…', 'The Caribbean diaspora is not just a community abroad. It is a bridge between th', 'heritage', 2026, 'Diaspora caribéenne', ARRAY['eng'], 'The Caribbean diaspora is not just a community abroad. It is a bridge between the islands and the world. It brings resources back, sends culture forward, and keeps the conversation going across oceans.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La diaspora haïtienne est une force. Elle envoie de l''argent, du…', 'Diaspora ayisyèn an se yon fòs. Yo voye lajan, yo voye sipò, yo kenbe kilti a vi', 'heritage', 2026, 'Diaspora caribéenne', ARRAY['hat'], 'Diaspora ayisyèn an se yon fòs. Yo voye lajan, yo voye sipò, yo kenbe kilti a vivan lwen peyi a. Menm lwen, yo rete ayisyen. Menm lwen, yo rete konekte.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'En Martinique, la peinture raconte l''histoire. La Martinique est une…', 'En Matinik, penti-a ka rakonté listwa. Matinik sé yon ti zil ki pwoduyi gran ati', 'visual_arts', 2026, 'Martinique', ARRAY['acf'], 'En Matinik, penti-a ka rakonté listwa. Matinik sé yon ti zil ki pwoduyi gran atizan. Chak toil ka palé a rasin a nou, a doulè a nou, a bèltè a nou.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L''art de rue jamaïcain parle au peuple dans le langage des couleurs.…', 'Jamaican street art talk to the people in the language of colour. From the mural', 'visual_arts', 2026, 'Jamaica', ARRAY['jam'], 'Jamaican street art talk to the people in the language of colour. From the murals of Kingston to the canvas of our painters — Jamaican art is loud, proud and always political.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L''art de Curaçao vit dans nos rues colorées. Les maisons de Punda,…', 'Arte di Kòrsou ta bibo den nos kaya kolorido. E kas di Punda, e pinturanan di no', 'visual_arts', 2026, 'Curacao', ARRAY['pap'], 'Arte di Kòrsou ta bibo den nos kaya kolorido. E kas di Punda, e pinturanan di nos artistanan — tur esei ta konta e storia di nos pueblo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les jeunes Surinamiens utilisent les réseaux sociaux pour parler le…', 'Jongomans Sranan e yus sosyal media fu taki Sranan Tongo. Den e bringa kulturu f', 'literary', 2026, 'Suriname', ARRAY['srn'], 'Jongomans Sranan e yus sosyal media fu taki Sranan Tongo. Den e bringa kulturu fu dem gi heri wortoe. Wan nyu fasi fu hori kulturu leki. Wan nyu fasi fu taki: mi de dya.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les jeunes Caribéens néerlandais utilisent les réseaux sociaux pour…', 'Jonge Caribische Nederlanders gebruiken sociale media om hun identiteit uit te d', 'literary', 2026, 'Curacao', ARRAY['nld'], 'Jonge Caribische Nederlanders gebruiken sociale media om hun identiteit uit te drukken. Ze praten Papiaments, ze dansen, ze koken — en de hele wereld kijkt mee.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'À Sainte-Lucie, la tradition du conte — le cercle de narration…', 'In Saint Lucia, the tradition of the conte — the Creole storytelling circle — st', 'literary', 2026, 'St Lucia', ARRAY['eng'], 'In Saint Lucia, the tradition of the conte — the Creole storytelling circle — still lives in the villages. Elders gather, children listen, and the old stories travel one more generation forward.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le théâtre cubain a une longue tradition. Du théâtre bufo du XIXe…', 'El teatro cubano tiene una larga tradición. Desde el teatro bufo del siglo XIX h', 'performing_arts', 2026, 'Cuba', ARRAY['spa'], 'El teatro cubano tiene una larga tradición. Desde el teatro bufo del siglo XIX hasta el teatro de la revolución — siempre ha sido un espacio para debatir, reír, llorar y pensar lo que somos.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les écrivains haïtiens écrivent dans leurs langues : français,…', 'Literati ayisyen yo ekri nan lang yo : fransè, kreyòl, oswa de lang ansanm. Yo p', 'literary', 2026, 'Haiti', ARRAY['hat'], 'Literati ayisyen yo ekri nan lang yo : fransè, kreyòl, oswa de lang ansanm. Yo pale soufrans, rezistans, espwa. Depi Jacques Roumain rive nan jenerasyon jodi a, literati ayisyèn an pa sispann pale.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les écrivains guadeloupéens écrivent en créole, en français, et…', 'Ékriven gwadloupéyen yo ka ékri an kréyol, an fransè, ék souvan nan tou-de. Simo', 'literary', 2026, 'Guadeloupe', ARRAY['gcf'], 'Ékriven gwadloupéyen yo ka ékri an kréyol, an fransè, ék souvan nan tou-de. Simone Schwarz-Bart, Maryse Condé — yo monté non Gwadloup douvan tout mond-lan. Lèkritir sé yon zam.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La littérature caribéenne a donné au monde Aimé Césaire, Derek…', 'Caribbean literature gave the world Aimé Césaire, Derek Walcott, CLR James, Jama', 'literary', 2026, 'Caribbean (général)', ARRAY['eng'], 'Caribbean literature gave the world Aimé Césaire, Derek Walcott, CLR James, Jamaica Kincaid. These writers did not write from the margins — they rewrote the center. They showed that our stories matter.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'En Martinique, la peinture raconte l histoire. Chaque toile parle de…', 'En Matinik, penti-a ka rakonté listwa. Chak toil ka palé a rasin a nou, a doulè ', 'visual_arts', 2026, 'Martinique', ARRAY['acf'], 'En Matinik, penti-a ka rakonté listwa. Chak toil ka palé a rasin a nou, a doulè a nou, a bèltè a nou.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L art de rue jamaïcain parle au peuple dans le langage des couleurs.…', 'Jamaican street art talk to the people in the language of colour. From the mural', 'visual_arts', 2026, 'Jamaica', ARRAY['jam'], 'Jamaican street art talk to the people in the language of colour. From the murals of Kingston to the canvas of our painters — Jamaican art is loud, proud and always political.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'L art de Curaçao vit dans nos rues colorées. Tout cela raconte l…', 'Arte di Kòrsou ta bibo den nos kaya kolorido. E kas di Punda, e pinturanan di no', 'visual_arts', 2026, 'Curacao', ARRAY['pap'], 'Arte di Kòrsou ta bibo den nos kaya kolorido. E kas di Punda, e pinturanan di nos artistanan — tur esei ta konta e storia di nos pueblo.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les jeunes Surinamiens utilisent les réseaux sociaux pour parler le…', 'Jongomans Sranan e yus sosyal media fu taki Sranan Tongo. Den e bringa kulturu f', 'literary', 2026, 'Suriname', ARRAY['srn'], 'Jongomans Sranan e yus sosyal media fu taki Sranan Tongo. Den e bringa kulturu fu dem gi heri wortoe. Wan nyu fasi fu taki: mi de dya.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les jeunes Caribéens néerlandais utilisent les réseaux sociaux pour…', 'Jonge Caribische Nederlanders gebruiken sociale media om hun identiteit uit te d', 'literary', 2026, 'Curacao', ARRAY['nld'], 'Jonge Caribische Nederlanders gebruiken sociale media om hun identiteit uit te drukken. Ze praten Papiaments, ze dansen, ze koken — en de hele wereld kijkt mee.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'À Sainte-Lucie, la tradition du conte vit encore dans les villages.…', 'In Saint Lucia, the tradition of the conte — the Creole storytelling circle — st', 'literary', 2026, 'St Lucia', ARRAY['eng'], 'In Saint Lucia, the tradition of the conte — the Creole storytelling circle — still lives in the villages. Elders gather, children listen, and the old stories travel one more generation forward.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Le théâtre cubain a une longue tradition. Il a toujours été un…', 'El teatro cubano tiene una larga tradición. Desde el teatro bufo del siglo XIX —', 'performing_arts', 2026, 'Cuba', ARRAY['spa'], 'El teatro cubano tiene una larga tradición. Desde el teatro bufo del siglo XIX — siempre ha sido un espacio para debatir, reír, llorar y pensar lo que somos.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les écrivains haïtiens écrivent dans leurs langues. De Jacques…', 'Literati ayisyen yo ekri nan lang yo. Yo pale soufrans, rezistans, espwa. Depi J', 'literary', 2026, 'Haiti', ARRAY['hat'], 'Literati ayisyen yo ekri nan lang yo. Yo pale soufrans, rezistans, espwa. Depi Jacques Roumain rive nan jenerasyon jodi a, literati ayisyèn an pa sispann pale.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'Les écrivains guadeloupéens écrivent en créole, en français. Simone…', 'Ékriven gwadloupéyen yo ka ékri an kréyol, an fransè. Simone Schwarz-Bart, Marys', 'literary', 2026, 'Guadeloupe', ARRAY['gcf'], 'Ékriven gwadloupéyen yo ka ékri an kréyol, an fransè. Simone Schwarz-Bart, Maryse Condé — yo monté non Gwadloup douvan tout mond-lan.', 'validated'),
  ('00000000-0000-0000-0000-000000000001', 'La littérature caribéenne a donné au monde Aimé Césaire, Derek…', 'Caribbean literature gave the world Aimé Césaire, Derek Walcott, CLR James, Jama', 'literary', 2026, 'Caribbean (général)', ARRAY['eng'], 'Caribbean literature gave the world Aimé Césaire, Derek Walcott, CLR James, Jamaica Kincaid. They did not write from the margins — they rewrote the center.', 'validated');
